import React from "react";
import { Link } from "react-router-dom";
import teamData from "../app/api/team.json"; // Import your team data from a separate file
import Header from "./components/Header";
import Footer from "./components/Footer";
import { Helmet } from "react-helmet";

class Team extends React.Component {
	render() {
		return (
			<>
				<Helmet>
					<meta charSet="UTF-8" />
					<meta
						name="viewport"
						content="width=device-width, initial-scale=1.0"
					/>
					<title>CAIES Fondation - Team</title>
					<meta
						name="description"
						content="Discover CAIES Foundation's pioneering team leveraging ML to assess arsenicosis resilience, study cellular redox, and innovate in landslide mapping."
					/>
					<link rel="canonical" href="https://caienvsus.org/about" />
					<meta
						name="keywords"
						content="caies foundation, artificial intelligence, environmental sustainability, non-profit organization, publication, publications"
					/>
					<meta name="author" content="CAIES Foundation" />
				</Helmet>
				<Header />
					<div className="team-pager-header">
						<div className="container">
							<div className="page-content">
								<h2>Team</h2>
								<p>
								Innovating together, forging pathways, transforming futures<br/>with unity and resilience.
								</p>
								<ol className="breadcrumb">
									<li className="breadcrumb-item">
										<Link to="/">Home</Link>
									</li>
									<li className="breadcrumb-item active">Team</li>
								</ol>
							</div>
						</div>
					</div>
					<section className="team-section bg-grey bd-bottom padding">
						<div className="container">
							<div className="section-heading text-center mb-40">
								<h2>Meet Our Team</h2>
							</div>
							<h3
								align="left"
								style={{ paddingLeft: "2.5%", paddingBottom: "3%", fontSize: "1.85rem" }}
							>
								The Advisory Team
							</h3>
							<div className="team-wrapper row" style={{paddingLeft: "2.5%",}}>
								{teamData.intellectualAdvisors.map((advisor, index) => (
									<div className="col-md-3 xs-padding" key={index}>
										<div className="team-details" style={{marginBottom: "12%"}}>
											<a href={advisor.linkedinUrl}>
												<img src={advisor.imageUrl} alt="team" />
												<div className="hover">
													<h3>
														{advisor.name} <span>{advisor.role}</span>
													</h3>
												</div>
											</a>
										</div>
									</div>
								))}
							</div>
							<h3
								align="left"
								style={{
									paddingLeft: "2.5%",
									paddingBottom: "2%", 
									fontSize: "1.85rem"
								}}
							>
								Scholars
							</h3>
							<div className="team-wrapper row" style={{paddingLeft: "2.5%",}}>
								{teamData.scholars.map((scholar, index) => (
									<div className="col-md-3 xs-padding" key={index}>
										<div className="team-details" style={{marginBottom: "12%"}}>
											<a href={scholar.linkedinUrl}>
												<img src={scholar.imagePath} alt="team"/>
												<div className="hover">
													<h3>
														{scholar.name} <span>{scholar.role}</span>
													</h3>
												</div>
											</a>
										</div>
									</div>
								))}
							</div>
							<h3
								align="left"
								style={{
									paddingLeft: "2.5%",
									paddingBottom: "2%",
									fontSize: "1.85rem"
								}}
							>
								Collaborators
							</h3>
							<div className="team-wrapper row" style={{paddingLeft: "2.5%",}}>
								{teamData.collaborators.map((collaborator, index) => (
									<div className="col-md-3 xs-padding" key={index}>
										<div className="team-details" style={{marginBottom: "12%"}}>
											<a href={collaborator.linkedinUrl}>
												<img src={collaborator.imageUrl} alt="team" />
												<div className="hover">
													<h3>
														{collaborator.name} <span>{collaborator.role}</span>
													</h3>
												</div>
											</a>
										</div>
									</div>
								))}
							</div>
						</div>
					</section>
				<Footer	/>
			</>
		);
	}
}

export default Team;