import React from "react";
import Header from "./components/Header";
import Footer from "./components/Footer";
import { Link } from "react-router-dom";
import { Helmet } from "react-helmet-async";

// Import the JSON data
import publicationData from "../app/api/publication.json";

class Publication extends React.Component {
	constructor(props) {
		super(props);
		this.state = {
			currentPage: 1,
			postsPerPage: 6,
		};
	}

	render() {
		const indexOfLastPost = this.state.currentPage * this.state.postsPerPage;
		const indexOfFirstPost = indexOfLastPost - this.state.postsPerPage;
		const currentPosts = publicationData.slice(
			indexOfFirstPost,
			indexOfLastPost
		);

		const paginate = (pageNumber) => {
			this.setState({ currentPage: pageNumber });
		};

		return (
			<>
				<Helmet>
					<meta charSet="UTF-8" />
					<meta
						name="viewport"
						content="width=device-width, initial-scale=1.0"
					/>
					<title>CAIES Fondation - Publications</title>
					<meta
						name="description"
						content="From curious minds to groundbreaking discoveries—your gateway to scholarly excellence"
					/>
					<link rel="canonical" href="https://caienvsus.org/publication" />
					<meta
						name="keywords"
						content="caies foundation, artificial intelligence, environmental sustainability, non-profit organization, publication, publications"
					/>
					<meta name="author" content="CAIES Foundation" />
				</Helmet>
				<Header />
				<div className="publication-pager-header">
					<div className="container">
						<div className="page-content">
							<h2>Publications</h2>
							<p>
							From curious minds to groundbreaking <br/>discoveries—your gateway to scholarly excellence
							</p>
							<ol className="breadcrumb">
								<li className="breadcrumb-item">
									<Link to="/">Home</Link>
								</li>
								<li className="breadcrumb-item active">Publications</li>
							</ol>
						</div>
					</div>
				</div>
				<section className="blog-section bg-grey padding">
					<div className="container">
						<div className="row">
							<div className="col-lg-12 xs-padding">
								<div className="blog-items grid-list row">
									{currentPosts.map((publication) => (
										<div className="col-md-4 padding-15" key={publication.id}>
											<div className="blog-post">
												<img src={publication.image} alt="blog post" />
												<div className="blog-content">
													<span className="date">
														<i className="fa fa-clock-o" /> {publication.date}
													</span>
													<h3>
														<a href={publication.link}>{publication.title}</a>
													</h3>
													<p>{publication.description}</p>
													<a href={publication.link} className="post-meta">
														Read More
													</a>
												</div>
											</div>
										</div>
									))}
								</div>
								<ul className="pagination_wrap align-center mt-30">
									<li>
										<a
											href="/#"
											onClick={(e) => {
												e.preventDefault();
												const newPage = this.state.currentPage - 1;
												if (newPage > 0) {
													paginate(newPage);
												}
											}}
										>
											<i className="ti-arrow-left"></i>
										</a>
									</li>
									{Array.from({
										length: Math.ceil(
											publicationData.length / this.state.postsPerPage
										),
									}).map((_, index) => (
										<li key={index + 1}>
											<a
												href="/#"
												onClick={(e) => {
													e.preventDefault();
													paginate(index + 1);
												}}
												className={
													this.state.currentPage === index + 1 ? "active" : ""
												}
											>
												{index + 1}
											</a>
										</li>
									))}
									<li>
										<a
											href="/#"
											onClick={(e) => {
												e.preventDefault();
												const newPage = this.state.currentPage + 1;
												if (
													newPage <=
													Math.ceil(
														publicationData.length / this.state.postsPerPage
													)
												) {
													paginate(newPage);
												}
											}}
										>
											<i className="ti-arrow-right"></i>
										</a>
									</li>
								</ul>
							</div>
						</div>
					</div>
				</section>
				<Footer />
			</>
		);
	}
}

export default Publication;
