import React from "react";
import Header from "./components/Header";
import Footer from "./components/Footer";
import { Link } from "react-router-dom";
import { Helmet } from "react-helmet-async";

const Awards = () => {
	return (
		<>
			<Helmet>
				<meta charSet="UTF-8" />
				<meta
					name="viewport"
					content="width=device-width, initial-scale=1.0"
				/>
				<title>CAIES Fondation - Awards</title>
				<meta
					name="description"
					content="Explore CAIES Foundation's prestigious awards honoring unsung heroes in education and science from Indian government institutions. Nominate or apply now!"
				/>
				<link rel="canonical" href="https://caienvsus.org/awards" />
				<meta
					name="keywords"
					content="caies foundation, artificial intelligence, environmental sustainability, non-profit organization, publication, publications"
				/>
				<meta name="author" content="CAIES Foundation" />
			</Helmet>
			<Header />
			<div className="pager-header">
				<div className="container">
					<div className="page-content">
						<h2>Awards</h2>
						<p>
						Honoring unsung heroes in education<br/> science across India. Nominate now!
						</p>
						<ol className="breadcrumb">
							<li className="breadcrumb-item">
								<Link to="/">Home</Link>
							</li>
							<li className="breadcrumb-item active">Awards</li>
						</ol>
					</div>
				</div>
			</div>
			<section className="causes-section bg-grey bd-bottom padding">
				<div className="container">
					<div className="section-heading text-center mb-40">
						<h2 style={{ fontWeight: "900" }}>Awards</h2>
						<span className="heading-border" />
						<p>
						<b>The nominations are open on a rolling basis, and the awards will be announced on every Basant Panchami every year</b><br/><br/>
						
							The CAIES Foundation has launched various awards for unsung teachers and scientists, primarily from government schools, colleges, and universities. The foundation will select the awardee based on their academic, scientific, and social contributions. Although the foundation will perform its assessment for potential awardees, it also encourages individuals to submit their nominations through the foundation's website. The jurisdiction of the awards will be India. Nominations are open on a rolling basis; however, the application should be submitted by Makar Sankranti (January 15th) of each year. The awards will be announced on Vasant Panchami (February) every year. Applications submitted after Makar Sankranti will be considered for next year’s awards.
						</p>
					</div>
					<div className="causes-wrap row">
						<div className="col-md-4 xs-padding">
							<div className="causes-content">
								<div className="causes-thumb">
									<img src="../../assets/img/award-1.jpg" alt="causes" />
									<a href="https://docs.google.com/forms/d/e/1FAIpQLSe2AfR2lAvocqZuXJ8fpOnyoE7iQl5uchoYFYaZ0kaHKKxE-Q/viewform" className="submit-btn">
										Submit Application
										<i className="ti-plus" />
									</a>
								</div>
								<div className="causes-details">
									<h3>Teacher of the Year Award (for government school teachers only)</h3>
									<p>
										One teacher will be selected from each district for Primary, Middle, and high schools. There will be a one-time application submission fee of Rs.501/-. There will not be any other fees for receiving the award or any other purposes.
									</p>
								</div>
							</div>
						</div>
						<div className="col-md-4 xs-padding">
							<div className="causes-content">
								<div className="causes-thumb">
									<img src="../../assets/img/award-2.jpg" alt="causes" />
									<a href="https://docs.google.com/forms/d/e/1FAIpQLSe2AfR2lAvocqZuXJ8fpOnyoE7iQl5uchoYFYaZ0kaHKKxE-Q/viewform" className="submit-btn">
										Submit Application
										<i className="ti-plus" />
									</a>
								</div>
								<div className="causes-details">
									<h3>Young Scientist of the Year Award (for scientists up to 35 years of age)</h3>
									<p>
										This award will be given to one Scientist per district. There will be a one-time application submission fee of Rs.501/-. There will not be any other fees for receiving the award or any other purposes.
									</p>
								</div>
							</div>
						</div>

						<div className="col-md-4 xs-padding" style={{ paddingBottom: "25px" }}>
							<div className="causes-content">
								<div className="causes-thumb">
									<img src="../../assets/img/award-5.jpg" alt="causes" />
									<a href="https://docs.google.com/forms/d/e/1FAIpQLSe2AfR2lAvocqZuXJ8fpOnyoE7iQl5uchoYFYaZ0kaHKKxE-Q/viewform" className="submit-btn">
										Submit Application
										<i className="ti-plus" />
									</a>
								</div>
								<div className="causes-details">
									<h3>Independent Scientist of the Year Award (for independent researchers)</h3>
									<p>
										This award will be given to one independent Scientist per district. There will be a one-time application submission fee of Rs.501/-. There will not be any other fees for receiving the award or any other purposes.
									</p>
								</div>
							</div>
						</div>

						<div className="col-md-4 xs-padding" style={{ paddingTop: "25px" }}>
							<div className="causes-content">
								<div className="causes-thumb">
									<img src="../../assets/img/award-3.jpg" alt="causes" />
									<a href="https://docs.google.com/forms/d/e/1FAIpQLSe2AfR2lAvocqZuXJ8fpOnyoE7iQl5uchoYFYaZ0kaHKKxE-Q/viewform" className="submit-btn">
										Submit Application
										<i className="ti-plus" />
									</a>
								</div>
								<div className="causes-details">
									<h3>Faculty Scientist of the Year Award (for university faculties' teaching and research accomplishments)</h3>
									<p>
										This award will be given to one faculty scientist per district. There will be a one-time application submission fee of Rs.1001/-. There will not be any other fees for receiving the award or any other purposes.
									</p>
								</div>
							</div>
						</div>

						<div className="col-md-4 xs-padding">
							<div className="causes-content">
								<div className="causes-thumb">
									<img src="../../assets/img/award-4.jpg" alt="causes" />
									<a href="https://docs.google.com/forms/d/e/1FAIpQLSe2AfR2lAvocqZuXJ8fpOnyoE7iQl5uchoYFYaZ0kaHKKxE-Q/viewform" className="submit-btn">
										Submit Application
										<i className="ti-plus" />
									</a>
								</div>
								<div className="causes-details">
									<h3>Industry Scientist of the Year Award (for industry professionals)</h3>
									<p>
										This award will be given to one industry scientist per state. There will be a one-time application submission fee of Rs.5001/-. There will not be any other fees for receiving the award or any other purposes.
									</p>
								</div>
							</div>
						</div>

						
					</div>
				</div>
			</section>
			<Footer />
		</>
	);
};

export default Awards;
