import React, { useState, useEffect } from "react";
import { animateScroll as scroll } from "react-scroll";
import ReactGA from 'react-ga';

const Footer = () => {
    const [visitorCount, setVisitorCount] = useState(0);

    useEffect(() => {
        // Fetch visitor count from your backend or analytics service
        // For demonstration purposes, let's initialize it with a random number
        const fetchedVisitorCount = Math.floor(Math.random() * 1000); // Replace this with actual data retrieval

        setVisitorCount(fetchedVisitorCount);

        // Track page view
        ReactGA.pageview(window.location.pathname + window.location.search);
    }, []);

    const scrollToTop = () => {
        scroll.scrollToTop({ duration: 500 }); // Adjust duration as needed
    };

    return (
        <>
            <footer className="footer-section">
                <div className="container">
                    <div className="row">
                        <div className="col-md-6 sm-padding">
                            <div className="copyright">© 2024 The CAIES Foundation</div>
                        </div>
                        <div className="col-md-6 sm-padding">
                            <ul className="footer-social">
                                <li>
                                    <a href="https://twitter.com/CaiesF" data-text="tw"><i className="fa fa-twitter"></i></a>
                                </li>
                                <li>
                                    <a href="/#" data-text="li"><i className="fa fa-linkedin"></i></a>
                                </li>
                                <li>
                                    <a href="https://www.instagram.com/caiesfoundation/" data-text="in"><i className="fa fa-instagram"></i></a>
                                </li>
                                <li>
                                    <a href="https://www.facebook.com/caiesfoundation/" data-text="fb"><i className="fa fa-facebook"></i></a>
                                </li>
                                <li>
                                    <a href="https://www.youtube.com/channel/UClV_dab_loUKR15sqD1EYeA" data-text="yt"><i className="fa fa-youtube"></i></a>
                                </li>
                                <li>
                                    <p style={{color: "white", fontSize: "14px", paddingLeft: "30px"}}>People Visited: {visitorCount}</p>
                                </li>
                            </ul>
                        </div>
                    </div>
                </div>
            </footer>

            <button
                id="scroll-to-top"
                onClick={(e) => {
                    e.preventDefault();
                    scrollToTop();
                }}
                style={{ outline: 'none', cursor: 'pointer' }}
            >
                <i className="arrow_up" />
            </button>
        </>
    );
};

export default Footer;