import React, { useEffect, useState } from "react";
import Header from "./components/Header";
import Footer from "./components/Footer";
import { useForm } from "@formspree/react";
import { Link } from 'react-router-dom';
import { Helmet } from "react-helmet-async";
// import { withGoogleMap, GoogleMap, Marker } from "react-google-maps";

const Contact = () => {
	const [state, handleSubmit] = useForm("mqkraboa");
	const [formStatus, setFormStatus] = useState(""); // "success" or "error"
	const [captchaValue, setCaptchaValue] = useState("");
	const [randomNumbers, setRandomNumbers] = useState(generateRandomNumbers());

	useEffect(() => {
		// Load Google Maps script
		const script = document.createElement("script");
		script.src = "https://maps.googleapis.com/maps/api/js?key=AIzaSyAT5eb2FuHM3uY9f2Xsadn0eR3o1zH_xVg";
		script.async = true;

		// Error handling for script loading
		script.onerror = () => {
			console.error("Error loading Google Maps script.");
		};

		script.onload = initMap;
		document.body.appendChild(script);

		return () => {
			document.body.removeChild(script);
		};
	}, []);

	const initMap = () => {
		// Google Maps initialization
		if (window.google && window.google.maps) {
			var mapOptions = {
				zoom: 11,
				center: new window.google.maps.LatLng(25.580717086791992,85.09457397460938),
				scrollwheel: false,
				navigationControl: false,
				mapTypeControl: false,
				scaleControl: false,
				draggable: false,
				styles: [{ "featureType": "administrative", "elementType": "all", "stylers": [{ "saturation": "-100" }] }, { "featureType": "administrative.province", "elementType": "all", "stylers": [{ "visibility": "off" }] }, { "featureType": "landscape", "elementType": "all", "stylers": [{ "saturation": -100 }, { "lightness": 65 }, { "visibility": "on" }] }, { "featureType": "poi", "elementType": "all", "stylers": [{ "saturation": -100 }, { "lightness": "50" }, { "visibility": "simplified" }] }, { "featureType": "road", "elementType": "all", "stylers": [{ "saturation": "-100" }] }, { "featureType": "road.highway", "elementType": "all", "stylers": [{ "visibility": "simplified" }] }, { "featureType": "road.arterial", "elementType": "all", "stylers": [{ "lightness": "30" }] }, { "featureType": "road.local", "elementType": "all", "stylers": [{ "lightness": "40" }] }, { "featureType": "transit", "elementType": "all", "stylers": [{ "saturation": -100 }, { "visibility": "simplified" }] }, { "featureType": "water", "elementType": "geometry", "stylers": [{ "hue": "#ffff00" }, { "lightness": -25 }, { "saturation": -97 }] }, { "featureType": "water", "elementType": "labels", "stylers": [{ "lightness": -25 }, { "saturation": -100 }] }]
			};

			var mapElement = document.getElementById('google_map');

			var map = new window.google.maps.Map(mapElement, mapOptions);
			// eslint-disable-next-line
			var marker = new window.google.maps.Marker({
				position: new window.google.maps.LatLng(25.580717086791992,85.09457397460938),
				map: map,
				title: 'Location!'
			});
		} else {
			console.error("Google Maps API not loaded.");
		}
	};


	function generateRandomNumbers() {
		const num1 = Math.floor(Math.random() * 10);
		const num2 = Math.floor(Math.random() * 10);
		return { num1, num2 };
	}

	const handleFormSubmit = async (e) => {
		e.preventDefault();

		// Check if the captcha is correct
		const expectedSum = randomNumbers.num1 + randomNumbers.num2;
		if (parseInt(captchaValue, 10) !== expectedSum) {
			alert("Please solve the math problem correctly.");
			return;
		}

		try {
			await handleSubmit(e);
			if (state.succeeded) {
				setFormStatus("success");
			} else {
				setFormStatus("error");
			}
		} catch (error) {
			console.error("Error submitting form:", error);
			setFormStatus("error");
		}
	};

	const handleCaptchaChange = (e) => {
		setCaptchaValue(e.target.value);
	};

	const handleRefreshCaptcha = () => {
		setRandomNumbers(generateRandomNumbers());
		setCaptchaValue("");
	};

	// const GoogleMapComponent = withGoogleMap(() => (
	//     <GoogleMap
	//         defaultCenter={{ lat: 40.6700, lng: -73.9400 }}
	//         defaultZoom={11}
	//     >
	//         <Marker position={{ lat: 40.6700, lng: -73.9400 }} />
	//     </GoogleMap>
	// ));

	return (
		<>
			<Helmet>
				<meta charSet="UTF-8" />
				<meta
					name="viewport"
					content="width=device-width, initial-scale=1.0"
				/>
				<title>CAIES Fondation - Contact</title>
				<meta
					name="description"
					content="Connect with CAIES Foundation to collaborate, inquire, or support our mission. Reach out through our contact page for partnerships, inquiries, or donations."
				/>
				<link rel="canonical" href="https://caienvsus.org/contact" />
				<meta
					name="keywords"
					content="caies foundation, artificial intelligence, environmental sustainability, non-profit organization, publication, publications"
				/>
				<meta name="author" content="CAIES Foundation" />
			</Helmet>
			<Header />
			<div className="pager-header">
				<div className="container">
					<div className="page-content">
						<h2>Contact With Us</h2>
						<p>
						Contact CAIES Foundation for collaboration,inquiries, and support.<br/>Connect with us today
						</p>
						<ol className="breadcrumb">
							<li className="breadcrumb-item">
								<Link to="/">Home</Link>
							</li>
							<li className="breadcrumb-item active">Contact</li>
						</ol>
					</div>
				</div>
			</div>
			<section className="contact-section padding">
				<div id="google_map"></div>
				<div className="container">
					<div className="row contact-wrap">
						<div className="col-md-6 xs-padding">
							<div className="contact-info">
								<h3>Office</h3>
								<br />
								<br />
								<br />
								<br />
								<p>
									CAIES Foundation, New Harnichak, Walmichak Road, Near
									Devisthan, Anisabad, Patna 800002, Bihar, India
								</p>
								<ul>
									<li>
										<i className="ti-mobile" /> +91 7739711077
									</li>
									<li>
										<i className="ti-email" /> contact@caienvsus.org
									</li>
								</ul>
							</div>
						</div>
						<div className="col-md-6 xs-padding">
							<div className="contact-form">
								<h3>Drop us a line</h3>
								{formStatus === "success" ? (
									<p>Thanks for your message!</p>
								) : (
									<form
										onSubmit={handleFormSubmit}
										className="form-horizontal"
									>
										<div className="form-group colum-row row">
											<div className="col-sm-6">
												<input
													type="text"
													id="name"
													name="name"
													className="form-control"
													placeholder="Name"
													required=""
												/>
											</div>
											<div className="col-sm-6">
												<input
													type="email"
													id="email"
													name="email"
													className="form-control"
													placeholder="Email"
													required=""
												/>
											</div>
										</div>
										<div className="form-group row">
											<div className="col-md-12">
												<textarea
													id="message"
													name="message"
													cols={30}
													rows={5}
													className="form-control message"
													placeholder="Message"
													required=""
													defaultValue={""}
												/>
												<label htmlFor="captcha"><br />
													Solve the math problem: {randomNumbers.num1} +{" "}
													{randomNumbers.num2} = ?
													<button
														type="button"
														className="btn btn-link"
														style={{ color: "#FE5F00", fontWeight: "bold" }}
														onClick={handleRefreshCaptcha}>
														<i className="ti-reload" />
													</button>
												</label>
												<input
													type="number"
													id="captcha"
													name="captcha"
													className="form-control"
													placeholder="Your answer"
													value={captchaValue}
													onChange={handleCaptchaChange}
													required=""
												/>
											</div>
										</div>
										<div className="form-group row">
											<div className="col-md-12">
												<button
													id="submit"
													className="default-btn"
													type="submit"
												>
													Send Message
												</button>
											</div>
										</div>
										<div
											id="form-messages"
											className={`alert ${formStatus}`}
											role="alert"
										>
											{formStatus === "error" && (
												<p>Oops! Something went wrong. Please try again.</p>
											)}
										</div>
									</form>
								)}
							</div>
						</div>
					</div>
				</div>
			</section>
			<Footer />
		</>
	);
};

export default Contact;