import React, { useState, useEffect, useRef } from "react";

const Counter = () => {
  const [moneyCount, setMoneyCount] = useState(990);
  const [volunteerCount, setVolunteerCount] = useState(0);
  const [peopleCount, setPeopleCount] = useState(240);
  const [feedbackCount, setFeedbackCount] = useState(0);
  const counterRef = useRef(null);

  const startCounter = (setCounter, limit, step = 1) => {
    const intervalId = setInterval(() => {
      setCounter((prevCount) => (prevCount < limit ? prevCount + step : prevCount));
    }, 1);

    // Cleanup the interval when the component is unmounted or count reaches the limit
    return () => clearInterval(intervalId);
  };

  useEffect(() => {
    const options = {
      root: null,
      rootMargin: "0px",
      threshold: 0.5, // Trigger when half of the element is in the viewport
    };

    const observer = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          startCounter(setMoneyCount, 1000, 5);
          startCounter(setVolunteerCount, 10);
          startCounter(setPeopleCount, 250);
          startCounter(setFeedbackCount, 10);
          observer.unobserve(entry.target);
        }
      });
    }, options);

    if (counterRef.current) {
      observer.observe(counterRef.current);
    }

    return () => {
      observer.disconnect();
    };
  }, []);

  return (
    <section id="counter" className="counter-section" ref={counterRef}>
      <div className="container">
        <ul className="row counters">
          <li className="col-md-3 col-sm-6 sm-padding">
            <div className="counter-content">
              <i className="ti-money" />
              <h3 className="counter">{moneyCount}</h3>
              <h4 className="text-white">Sponsored</h4>
            </div>
          </li>
          <li className="col-md-3 col-sm-6 sm-padding">
            <div className="counter-content">
              <i className="ti-face-smile" />
              <h3 className="counter">{volunteerCount}</h3>
              <h4 className="text-white">Scholars Around The World</h4>
            </div>
          </li>
          <li className="col-md-3 col-sm-6 sm-padding">
            <div className="counter-content">
              <i className="ti-user" />
              <h3 className="counter">{peopleCount}</h3>
              <h4 className="text-white">People Impacted</h4>
            </div>
          </li>
          <li className="col-md-3 col-sm-6 sm-padding">
            <div className="counter-content">
              <i className="ti-comments" />
              <h3 className="counter">{feedbackCount}</h3>
              <h4 className="text-white">Intellectual Support</h4>
            </div>
          </li>
        </ul>
      </div>
    </section>
  );
};

export default Counter;