import React from "react";
import OwlCarousel from "react-owl-carousel";
import "owl.carousel/dist/assets/owl.carousel.css"; // Import Owl Carousel styles
import "../../app/css/main.css";

class Events extends React.Component {
	render() {
		const owlCarouselOptions = {
			loop: true,
			margin: 10,
			responsiveClass: true,
			nav: true,
			autoplay: false,
			dots: false,
			responsive: {
				0: {
					items: 1,
				},
				600: {
					items: 1,
				},
				1000: {
					items: 2,
				},
			},
			navText: [
				"<span class='custom-nav-prev'>&lt;prev</span><span>&ensp;</span>",
				"<span class='custom-nav-next'>next&gt;</span>",
			],
		};

		return (
			<section className="events-section bg-grey bd-bottom padding">
				<style>
					{`
						.owl-prev, .owl-next {
							margin-top: 10px !important;
						}
						.owl-prev:focus, .owl-next:focus {
							outline: none !important;
						}
					`}
				</style>
				<div className="container">
					<div className="section-heading text-center mb-40">
						<h2>Events</h2>
						<span className="heading-border"></span>
						<p style={{fontFamily: 'Poppins', color: '#000', fontWeight: '300'}}>
							स्वस्मै स्वल्पं समाजाय सर्वस्वं - A little for self and everything for others
						</p>
					</div>
					<OwlCarousel className="events-wrap" {...owlCarouselOptions}>
						<div className="events-item">
							<div className="event-thumb">
								<img src="../../assets/img/events-1.jpg" alt="events" />
							</div>
							<div className="event-details">
								<h3>Deepawali Celebration Among Musahar Community</h3>
								<div className="event-info">
									<p>
										<i className="ti-calendar"></i>2022
									</p>
									<p>
										<i className="ti-location-pin"></i>Bihar, India.
									</p>
								</div>
								<p>
									In 2022, Deepawali was celebrated among the Musahar community in Bihar, India, marked by cultural festivities and communal gatherings.
								</p>
								<a href="/#" className="default-btn">
									Read More
								</a>
							</div>
						</div>
						<div className="events-item">
							<div className="event-thumb">
								<img src="../../assets/img/events-2.jpg" alt="events" />
							</div>
							<div className="event-details">
								<h3>Deepawali celebration with the Musahar community</h3>
								<div className="event-info">
									<p>
										<i className="ti-calendar"></i>2023
									</p>
									<p>
										<i className="ti-location-pin"></i>Bihar, India.
									</p>
								</div>
								<p>
									In 2023, Deepawali was celebrated among the Musahar community in Bihar, India, marked by cultural festivities and communal gatherings.
								</p>
								<a href="/#" className="default-btn">
									Read More
								</a>
							</div>
						</div>
						<div className="events-item">
							<div className="event-thumb">
								<img src="../../assets/img/events-3.jpg" alt="events" />
							</div>
							<div className="event-details">
								<h3>Aaranyakam - KDU</h3>
								<div className="event-info">
									<p>
										<i className="ti-calendar"></i>2023
									</p>
									<p>
										<i className="ti-location-pin"></i>Kerala, India.
									</p>
								</div>
								<p>
									In 2023, Kerala University of Digital Sciences Student Council, with School of Informatics, celebrated Wildlife Week with events promoting conservation.
								</p>
								<a href="/#" className="default-btn">
									Read More
								</a>
							</div>
						</div>
					</OwlCarousel>
				</div>
			</section>
		);
	}
}

export default Events;