import React from "react";

class Hero extends React.Component {
	render() {
		return (
			<>
				<section className="slider-section">
					<div className="slider-wrapper">
						<div id="main-slider" className="nivoSlider">
							<img src="../../assets/img/slider-1.jpg" alt="" title="#slider-caption-1" />
							<img src="../../assets/img/slider-2.jpg" alt="" title="#slider-caption-2" />
							<img src="../../assets/img/slider-3.jpg" alt="" title="#slider-caption-3" />
						</div>
						<div
							id="slider-caption-1"
							className="nivo-html-caption slider-caption"
						>
							<div className="display-table">
								<div className="table-cell">
									<div className="container">
										<div className="slider-text">
											<h5 className="wow cssanimation fadeInBottom">
												Join Us Today
											</h5>
											<h1 className="wow cssanimation fadeInBottom">
												Together we can
												<br />
												make a Difference
											</h1>
											<p
												className="wow cssanimation fadeInTop"
												data-wow-delay="1s"
											>
												The CAIES Foundation would extend its education,
												training, and research activities in other
												<br />
												areas required to address the sustainability issues.
											</p>
											<a
												href="/#"
												className="default-btn wow cssanimation fadeInBottom"
												data-wow-delay="0.8s"
											>
												Join Us
											</a>
										</div>
									</div>
								</div>
							</div>
						</div>
						<div
							id="slider-caption-2"
							className="nivo-html-caption slider-caption"
						>
							<div className="display-table">
								<div className="table-cell">
									<div className="container">
										<div className="slider-text">
											<h1
												className="hindi wow cssanimation fadeInTop"
												data-wow-delay="1s"
												data-wow-duration="800ms"
											>
												स्वस्मै स्वल्पं
												<br />
												समाजाय सर्वस्वं
											</h1>
											<p
												className="wow cssanimation fadeInBottom"
												data-wow-delay="1s"
											>
												CAIES generously promotes and supports research in
												fundamental and applied
												<br />
												science through internships for school students,
												undergraduate, postgraduate, and PhD students.
											</p>
											<a
												href="/#"
												className="default-btn wow cssanimation fadeInBottom"
												data-wow-delay="0.8s"
											>
												Join Us
											</a>
										</div>
									</div>
								</div>
							</div>
						</div>
						<div
							id="slider-caption-3"
							className="nivo-html-caption slider-caption"
						>
							<div className="display-table">
								<div className="table-cell">
									<div className="container">
										<div className="slider-text">
											<h5 className="wow cssanimation fadeInBottom">
												Join Us Today
											</h5>
											<h1 className="wow cssanimation fadeInBottom">
												The Center For Artificial Intelligence <br />
												&amp; Environmental Sustainability Foundation
											</h1>
											<p
												className="wow cssanimation fadeInTop"
												data-wow-delay="1s"
											>
												Our focus areas are centered around the six areas of
												environmental sustainability prioritized by the
												<br />
												World Economic Forum, Geneva, Switzerland and the
												Sustainable Development Goals set by the United Nations
											</p>
											<a
												href="/#"
												className="default-btn wow cssanimation fadeInBottom"
												data-wow-delay="0.8s"
											>
												Join Us
											</a>
										</div>
									</div>
								</div>
							</div>
						</div>
					</div>
				</section>
			</>
		);
	}
}

export default Hero;