import React, { useEffect } from "react";
import { useState } from "react";
import { Link } from "react-router-dom";
import "../../app/css/main.css";
import $ from "jquery";

// JSON data for menu items
const menuItems = [
    { id: 1, title: "Home", link: "/" },
    { id: 2, title: "About Us", link: "/about-us" },
    { id: 3, title: "Team", link: "/team" },
    { id: 4, title: "Awards", link: "/awards" },
    { id: 5, title: "Publications", link: "/publication" },
    // { id: 6, title: "News & Media", link: "/news-media" },
    // {
    //     id: 7, title: "Initiatives", subItems: [
    //         { id: 1, title: "PhD Academy", link: "/phd-academy" },
    //         { id: 2, title: "Vijñana Abhyudaya (Podcast)", link: "404.html" },
    //         { id: 3, title: "S2C (Podcast)", link: "causes.html" }
    //     ]
    // },
    { id: 8, title: "Contact", link: "/contact" }
];

const Header = () => {
    const [isSticky, setIsSticky] = useState(false);
    const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
    const [logoWidth, setLogoWidth] = useState("90%");

    useEffect(() => {
        const handleScroll = () => {
            const scrollY = window.scrollY;
            const sticky = scrollY > 0;
            setIsSticky(sticky);
        };

        window.addEventListener("scroll", handleScroll);

        return () => {
            window.removeEventListener("scroll", handleScroll);
        };
    }, []);

    useEffect(() => {
        const handleResize = () => {
            // Adjust logo width based on screen width
            const screenWidth = window.innerWidth;
            if (screenWidth < 768) {
                setLogoWidth("50%");
            } else {
                setLogoWidth("90%");
            }
        };

        // Call handleResize on initial load and on window resize
        handleResize();
        window.addEventListener("resize", handleResize);

        return () => {
            window.removeEventListener("resize", handleResize);
        };
    }, []);

    const toggleMenu = () => {
        setMobileMenuOpen(!mobileMenuOpen);
    };

    useEffect(() => {
        var header = $("#header"),
            height = header.height(),
            yOffset = 0,
            triggerPoint = 100;
        $('.header-height').css('height', height + 'px');
        $(window).on('scroll', function () {
            yOffset = $(window).scrollTop();

            if (yOffset >= triggerPoint) {
                header.removeClass("animated cssanimation fadeIn");
                header.addClass("navbar-fixed-top  cssanimation animated fadeInTop");
            } else {
                header.removeClass("navbar-fixed-top cssanimation  animated fadeInTop");
                header.addClass("animated cssanimation fadeIn");
            }
        });
    }, []);


    // Inside the Header component
    return (
        <>
            <style>{`
            .bottom-header.sticky {
                width: 100%; /* Add a fixed width for the header */
              }
              `}</style>
            {/* Header content */}
            <div className="site-preloader-wrap">
                <div className="spinner" />
            </div>
            <header id="header" className="header-section">
                {/* Top header */}
                <div className="top-header">
                    <div className="container">
                        <div className="top-content-wrap row">
                            <div className="col-sm-8">
                                <ul className="left-info">
                                    <li>
                                        <a href="mailto:contact@caienvsus.org">
                                            <i className="ti-email" />
                                            contact@caienvsus.org
                                        </a>
                                    </li>
                                    <li>
                                        <a href="tel:+917739711077">
                                            <i className="ti-mobile" /> +91 7739711077
                                        </a>
                                    </li>
                                </ul>
                            </div>
                            <div className="col-sm-4 d-none d-md-block">
                                <ul className="footer-social">
                                    <li>
                                        <a href="https://twitter.com/CaiesF" data-text="tw"><i className="fa fa-twitter"></i></a>
                                    </li>
                                    <li>
                                        <a href="/#" data-text="li"><i className="fa fa-linkedin"></i></a>
                                    </li>
                                    <li>
                                        <a href="https://www.instagram.com/caiesfoundation/" data-text="in"><i className="fa fa-instagram"></i></a>
                                    </li>
                                    <li>
                                        <a href="https://www.facebook.com/caiesfoundation/" data-text="fb"><i className="fa fa-facebook"></i></a>
                                    </li>
                                    <li>
                                        <a href="https://www.youtube.com/channel/UClV_dab_loUKR15sqD1EYeA" data-text="yt"><i className="fa fa-youtube"></i></a>
                                    </li>
                                </ul>
                            </div>
                        </div>
                    </div>
                </div>
                {/* Bottom header */}
                <div className={`bottom-header ${isSticky ? "sticky" : ""}`}>
                    <div className="container">
                        <div className="bottom-content-wrap justify-content-between align-items-center row">
                            <div className="col-sm-2 d-flex align-items-center">
                                {/* Site branding and mobile menu toggle */}
                                <div className="site-branding">
                                    <a href="/#">
                                        <img
                                            src="../../assets/img/logo.svg"
                                            width={logoWidth}
                                            alt="Brand"
                                        />
                                    </a>
                                </div>
                                <div className="d-md-none col-sm-8">
                                    <button className="mobile-menu-toggle" onClick={toggleMenu}>
                                        {mobileMenuOpen ? (
                                            <svg
                                                xmlns="http://www.w3.org/2000/svg"
                                                fill="none"
                                                viewBox="0 0 24 24"
                                                strokeWidth="1.5"
                                                stroke="currentColor"
                                                className="w-8 h-8"
                                            >
                                                <path
                                                    strokeLinecap="round"
                                                    strokeLinejoin="round"
                                                    d="M6 18 18 6M6 6l12 12"
                                                />
                                            </svg>
                                        ) : (
                                            <svg
                                                xmlns="http://www.w3.org/2000/svg"
                                                fill="none"
                                                viewBox="0 0 24 24"
                                                strokeWidth="1.5"
                                                stroke="currentColor"
                                                className="w-8 h-8"
                                            >
                                                <path
                                                    strokeLinecap="round"
                                                    strokeLinejoin="round"
                                                    d="M3.75 6.75h16.5M3.75 12h16.5M12 17.25h8.25"
                                                />
                                            </svg>
                                        )}
                                    </button>
                                </div>
                            </div>
                            <div className="col-sm-10 text-right">
                                {/* Main menu */}
                                <ul id="mainmenu" className="nav navbar-nav nav-menu">
                                    {menuItems.map(item => (
                                        <li key={item.id}>
                                            {item.subItems ? (
                                                // Render dropdown menu item
                                                <>
                                                    <a href="/#" className="dropdown-icon">
                                                        {item.title}
                                                    </a>
                                                    <ul>
                                                        {item.subItems.map(subItem => (
                                                            <li key={subItem.id}>
                                                                <Link to={subItem.link}>
                                                                    {subItem.title}
                                                                </Link>
                                                            </li>
                                                        ))}
                                                    </ul>
                                                </>
                                            ) : (
                                                // Render regular menu item
                                                <Link to={item.link}>{item.title}</Link>
                                            )}
                                        </li>
                                    ))}
                                </ul>
                                <Link to="/#" className="default-btn">
                                    Connect With Us
                                </Link>
                            </div>
                        </div>
                    </div>
                </div>
            </header>
            {/* Mobile menu */}
            <CustomMobileMenu mobileMenuOpen={mobileMenuOpen} toggleMenu={toggleMenu} menuItems={menuItems} />
            {/* <div className="header-height" /> */}
        </>
    );
};

// Custom Mobile Menu Component
const CustomMobileMenu = ({ mobileMenuOpen, toggleMenu, menuItems }) => {
    const [showPagesDropdown, setShowPagesDropdown] = useState(false);

    const togglePagesDropdown = () => {
        setShowPagesDropdown(!showPagesDropdown);
    };

    const handleDropdownLinkClick = (e) => {
        e.preventDefault(); // Prevent default behavior
        togglePagesDropdown(); // Toggle the dropdown
    };

    return (
        <div className={`mobile-menu ${mobileMenuOpen ? 'open' : ''}`}>
            <nav>
                <ul
                    className="mobile-menu-list"
                    style={{
                        textAlign: "left",
                        fontSize: "25px",
                        fontWeight: "600",
                        lineHeight: "1.8",
                        paddingBottom: "20px",
                        paddingLeft: "20px",
                    }}
                >
                    {menuItems.map(item => (
                        <li key={item.id}>
                            {item.subItems ? (
                                // Render dropdown menu item
                                <>
                                    <a href="/#" className="dropdown-icon" onClick={togglePagesDropdown}>
                                        {item.title}{' '}
                                        {showPagesDropdown ? (
                                            // Dropdown icon for opened dropdown
                                            <svg
                                                xmlns="http://www.w3.org/2000/svg"
                                                fill="none"
                                                viewBox="0 0 24 24"
                                                strokeWidth="1.5"
                                                stroke="currentColor"
                                                className="w-4 h-4"
                                                style={{ verticalAlign: "middle" }}
                                            >
                                                <path
                                                    strokeLinecap="round"
                                                    strokeLinejoin="round"
                                                    d="m4.5 15.75 7.5-7.5 7.5 7.5"
                                                />
                                            </svg>
                                        ) : (
                                            // Dropdown icon for closed dropdown
                                            <svg
                                                xmlns="http://www.w3.org/2000/svg"
                                                fill="none"
                                                viewBox="0 0 24 24"
                                                strokeWidth="1.5"
                                                stroke="currentColor"
                                                className="w-4 h-4"
                                                style={{ verticalAlign: "middle" }}
                                            >
                                                <path
                                                    strokeLinecap="round"
                                                    strokeLinejoin="round"
                                                    d="m19.5 8.25-7.5 7.5-7.5-7.5"
                                                />
                                            </svg>
                                        )}
                                    </a>
                                    {showPagesDropdown && (
                                        <ul style={{ paddingLeft: "20px" }}>
                                            {item.subItems.map(subItem => (
                                                <li key={subItem.id}>
                                                    <Link
                                                        to={subItem.link}
                                                        className={mobileMenuOpen ? "open-link" : ""}
                                                        onClick={handleDropdownLinkClick} // Prevent navigation
                                                    >
                                                        {subItem.title}
                                                    </Link>
                                                </li>
                                            ))}
                                        </ul>
                                    )}
                                </>
                            ) : (
                                // Render regular menu item
                                <Link to={item.link} className={mobileMenuOpen ? "open-link" : ""}>
                                    {item.title}
                                </Link>
                            )}
                        </li>
                    ))}
                </ul>
            </nav>
            <style>{`
                    .mobile-menu-toggle:focus {
                        outline: none;
                    }
                    .mobile-menu-toggle svg {
                        fill: none;
                        stroke: currentColor;
                        strokeWidth: 1.5;
                        width: 32px;
                        height: 32px;
                    }

                    .dropdown-icon svg {
                        fill: none;
                        display: inline;
                        vertical-align: middle;
                        stroke: currentColor;
                        strokeWidth: 1.5;
                        width: 24px; /* Adjust icon size as needed */
                        height: 24px; /* Adjust icon size as needed */
                    }

                    .open-link {
                        color: #000;
                    }

                    .mobile-menu {
                        position: fixed;
                        top: 70px; /* Adjust this value as needed */
                        right: 0;
                        bottom: 0;
                        background-color: #fff;
                        width: 100%; /* Adjust the width as needed */
                        height: 60%;
                        overflow-y: auto;
                        transition: transform 0.3s ease-in-out;
                        transform: translateX(${mobileMenuOpen ? '0' : '100%'});
                        z-index: 999;
                    }
                `}</style>
        </div>
    );
};


export default Header;